parameters.code:
if self.flash > 0:
    self.flash = self.flash - 1
    if self.flash == 0:
        g = self.grid
        marks = self.marked
        runs = self.marked_runs
        upgrade_specials = {}
        for cells, orientation in runs:
            if len(cells) >= 5:
                mid = cells[len(cells) // 2]
                upgrade_specials[mid] = ('color', g[mid[1]][mid[0]])
            elif len(cells) == 4:
                mid = cells[len(cells) // 2]
                upgrade_specials[mid] = ('row',) if orientation == 'h' else ('col',)
        extra = set()
        activated = False
        for cell in marks:
            kind = self.special.get(cell)
            if kind is None:
                continue
            activated = True
            if kind[0] == 'row':
                cy = cell[1]
                for xx2 in range(self.cols):
                    extra.add((xx2, cy))
            elif kind[0] == 'col':
                cx = cell[0]
                for yy2 in range(self.rows):
                    extra.add((cx, yy2))
            elif kind[0] == 'color':
                target_color = kind[1]
                for yy2 in range(self.rows):
                    for xx2 in range(self.cols):
                        if g[yy2][xx2] == target_color:
                            extra.add((xx2, yy2))
        all_cleared = marks | extra
        self.score = self.score + len(all_cleared) * 10
        destroy = all_cleared - set(upgrade_specials.keys())
        if upgrade_specials or activated:
            self._sound_queue.append('snd_special')
        final_special = {}
        falls = {}
        for xx in range(self.cols):
            kept = []
            for yy in range(self.rows):
                if (xx, yy) not in destroy:
                    kind = upgrade_specials.get((xx, yy))
                    if kind is None:
                        kind = self.special.get((xx, yy))
                    kept.append((yy, g[yy][xx], kind))
            new_count = self.rows - len(kept)
            for i in range(len(kept)):
                dst = new_count + i
                src = kept[i][0]
                g[dst][xx] = kept[i][1]
                if kept[i][2] is not None:
                    final_special[(xx, dst)] = kept[i][2]
                if dst != src:
                    falls[(xx, dst)] = (dst - src) * self.tile
            for dst in range(new_count):
                g[dst][xx] = random.randrange(4)
                falls[(xx, dst)] = new_count * self.tile
        self.special = final_special
        self.marked = set()
        self.marked_runs = []
        self.falling = falls
        if self.score >= self.target:
            self.advance_level()
        elif self.moves <= 0:
            self.lost = True
        if not self.won and not self.goto_room_target and not falls:
            new_marks, new_runs = self.find_matches(g, self.rows, self.cols)
            if new_marks:
                self.marked = new_marks
                self.marked_runs = new_runs
                self.flash = self.flash_total
                self.chain = self.chain + 1
                self._sound_queue.append('snd_cascade')
elif self.falling:
    done = True
    for key in list(self.falling.keys()):
        v = self.falling[key] - self.fall_speed
        if v > 0:
            self.falling[key] = v
            done = False
        else:
            self.falling[key] = 0
    if done:
        self.falling = {}
        if not self.won and not self.goto_room_target:
            new_marks, new_runs = self.find_matches(self.grid, self.rows, self.cols)
            if new_marks:
                self.marked = new_marks
                self.marked_runs = new_runs
                self.flash = self.flash_total
                self.chain = self.chain + 1
                self._sound_queue.append('snd_cascade')
elif self.swap_off:
    done = True
    for key in list(self.swap_off.keys()):
        dx, dy = self.swap_off[key]
        if dx > 0:
            dx = max(0, dx - self.swap_speed)
        elif dx < 0:
            dx = min(0, dx + self.swap_speed)
        if dy > 0:
            dy = max(0, dy - self.swap_speed)
        elif dy < 0:
            dy = min(0, dy + self.swap_speed)
        if dx != 0 or dy != 0:
            done = False
        self.swap_off[key] = (dx, dy)
    if done:
        self.swap_off = {}
        if self.swap_phase == 'forward':
            if self.pending_marks:
                self.marked = self.pending_marks
                self.marked_runs = self.pending_runs
                self.flash = self.flash_total
                self.chain = 0
                self._sound_queue.append('snd_match')
                self.swap_phase = None
                self.pending_marks = None
                self.pending_runs = []
                self.last_swap = None
            else:
                gx, gy, sx, sy = self.last_swap
                g = self.grid
                tmp = g[gy][gx]
                g[gy][gx] = g[sy][sx]
                g[sy][sx] = tmp
                self.arm_swap((gx, gy), (sx, sy))
                self.swap_phase = 'back'
        elif self.swap_phase == 'back':
            self.swap_phase = None
            self.pending_marks = None
            self.pending_runs = []
            self.last_swap = None

q = self._draw_queue
q.append({'type': 'rectangle', 'x1': self.ox - 10, 'y1': self.oy - 10, 'x2': self.ox + self.cols * self.tile + 10, 'y2': self.oy + self.rows * self.tile + 10, 'color': (52, 73, 94), 'filled': True})
blink_on = self.flash > 0 and (self.flash // 6) % 2 == 0
board_top = self.oy
for gy in range(self.rows):
    for gx in range(self.cols):
        color_idx = self.grid[gy][gx]
        off_x, off_y = self.swap_off.get((gx, gy), (0, 0))
        off_y = off_y + self.falling.get((gx, gy), 0)
        x1 = self.ox + gx * self.tile + 4 - off_x
        y1 = self.oy + gy * self.tile + 4 - off_y
        y2 = y1 + self.tile - 8
        if y2 <= board_top:
            continue
        if y1 < board_top:
            y1 = board_top
        marked_here = (gx, gy) in self.marked
        if marked_here and blink_on:
            q.append({'type': 'rectangle', 'x1': x1, 'y1': y1, 'x2': x1 + self.tile - 8, 'y2': y2, 'color': (255, 255, 255), 'filled': True})
        else:
            q.append({'type': 'sprite', 'sprite_name': self.sprite_names[color_idx], 'x': x1, 'y': y1})
            kind = self.special.get((gx, gy))
            if kind is not None:
                midx = (x1 + x1 + self.tile - 8) // 2
                midy = (y1 + y2) // 2
                if kind[0] == 'row':
                    q.append({'type': 'rectangle', 'x1': x1 + 4, 'y1': midy - 4, 'x2': x1 + self.tile - 12, 'y2': midy + 4, 'color': (255, 255, 255), 'filled': True})
                elif kind[0] == 'col':
                    q.append({'type': 'rectangle', 'x1': midx - 4, 'y1': y1 + 4, 'x2': midx + 4, 'y2': y2 - 4, 'color': (255, 255, 255), 'filled': True})
                elif kind[0] == 'color':
                    q.append({'type': 'ellipse', 'x1': x1 + 6, 'y1': y1 + 6, 'x2': x1 + self.tile - 14, 'y2': y2 - 6, 'color': (255, 255, 255), 'filled': False})
        if marked_here:
            for k in range(3):
                q.append({'type': 'rectangle', 'x1': x1 + k, 'y1': y1 + k, 'x2': x1 + self.tile - 8 - k, 'y2': y2 - k, 'color': (255, 255, 255), 'filled': False})
if self.sel is not None:
    for k in range(4):
        x1 = self.ox + self.sel[0] * self.tile + k
        y1 = self.oy + self.sel[1] * self.tile + k
        q.append({'type': 'rectangle', 'x1': x1, 'y1': y1, 'x2': x1 + self.tile - 2 * k, 'y2': y1 + self.tile - 2 * k, 'color': (255, 255, 255), 'filled': False})
q.append({'type': 'text', 'x': self.ox, 'y': self.oy - 76, 'text': 'Level ' + str(self.level_num) + '   Score: ' + str(self.score) + ' / ' + str(self.target), 'color': (30, 30, 30)})
q.append({'type': 'text', 'x': self.ox, 'y': self.oy - 56, 'text': 'Moves left: ' + str(self.moves), 'color': (30, 30, 30)})
q.append({'type': 'text', 'x': self.ox, 'y': self.oy + self.rows * self.tile + 26, 'text': 'Click a tile, then an adjacent tile to swap. Match 4+ for a special tile.', 'color': (60, 60, 60)})
if self.lost:
    q.append({'type': 'text', 'x': self.ox + 130, 'y': self.oy - 96, 'text': 'OUT OF MOVES - click to retry', 'color': (200, 30, 30)})
if self.won:
    q.append({'type': 'text', 'x': self.ox + 150, 'y': self.oy - 96, 'text': 'YOU WIN! ALL LEVELS CLEAR!', 'color': (200, 30, 30)})
